def process_job(job_data: Any):
    if isinstance(job_data, dict):
        job_type = job_data.get('job_type', 'unknown')
        logging.info(f'Processing job type: {job_type}')
        
        if job_type == 'data_processing':
            process_data_job(job_data)
        elif job_type == 'computation':
            process_computation_job(job_data)
        elif job_type == 'report_generation':
            process_report_job(job_data)
        else:
            logging.warning(f'Unknown job type: {job_type}')
            process_generic_job(job_data)
    elif isinstance(job_data, list):
        logging.info(f'Processing batch of {len(job_data)} items')
        for item in job_data:
            process_item(item)
    else:
        logging.info(f'Processing custom object: {type(job_data).__name__}')
        process_custom_object(job_data)


def process_data_job(job_data: dict):
    logging.info(f'Data processing job started')
    data = job_data.get('data', [])
    operation = job_data.get('operation', 'transform')
    
    result = []
    for item in data:
        if operation == 'transform':
            result.append(transform_data(item))
        elif operation == 'aggregate':
            result.append(aggregate_data(item))
    
    logging.info(f'Processed {len(result)} data items')
    store_result(job_data.get('job_id'), result)


def process_computation_job(job_data: dict):
    logging.info(f'Computation job started')
    numbers = job_data.get('numbers', [])
    operation = job_data.get('operation', 'sum')
    
    if operation == 'sum':
        result = sum(numbers)
    elif operation == 'average':
        result = sum(numbers) / len(numbers) if numbers else 0
    elif operation == 'max':
        result = max(numbers) if numbers else None
    else:
        result = None
    
    logging.info(f'Computation result: {result}')
    store_result(job_data.get('job_id'), result)


def process_report_job(job_data: dict):
    logging.info(f'Report generation job started')
    report_type = job_data.get('report_type', 'summary')
    data_source = job_data.get('data_source', [])
    
    report = generate_report(report_type, data_source)
    
    logging.info(f'Generated report with {len(report)} sections')
    store_result(job_data.get('job_id'), report)


def process_generic_job(job_data: dict):
    logging.info(f'Processing generic job')
    
    if 'parameters' in job_data:
        params = job_data['parameters']
        logging.info(f'Job parameters: {params}')
    
    result = {'status': 'completed', 'data': job_data}
    store_result(job_data.get('job_id', 'unknown'), result)


def process_item(item: Any):
    logging.info(f'Processing item: {type(item).__name__}')
    
    if hasattr(item, 'process'):
        item.process()
    elif isinstance(item, dict):
        for key, value in item.items():
            logging.info(f'  {key}: {value}')


def process_custom_object(obj: Any):
    logging.info(f'Processing custom object')
    
    if hasattr(obj, '__dict__'):
        attributes = vars(obj)
        logging.info(f'Object attributes: {list(attributes.keys())}')
        
        if hasattr(obj, 'execute'):
            obj.execute()
        elif hasattr(obj, 'run'):
            obj.run()
        else:
            logging.info(f'No execution method found on object')


def transform_data(item: Any) -> Any:
    if isinstance(item, dict):
        return {k: str(v).upper() if isinstance(v, str) else v for k, v in item.items()}
    return item


def aggregate_data(item: Any) -> Any:
    if isinstance(item, (list, tuple)):
        return sum(x for x in item if isinstance(x, (int, float)))
    return item


def generate_report(report_type: str, data_source: list) -> dict:
    report = {
        'type': report_type,
        'generated_at': 'timestamp',
        'sections': []
    }
    
    if report_type == 'summary':
        report['sections'].append({
            'title': 'Summary',
            'content': f'Total items: {len(data_source)}'
        })
    elif report_type == 'detailed':
        for idx, item in enumerate(data_source):
            report['sections'].append({
                'title': f'Item {idx + 1}',
                'content': str(item)
            })
    
    return report


def store_result(job_id: str, result: Any):
    logging.info(f'Storing result for job {job_id}')
    logging.info(f'Result: {result}')